INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('beast','system','UGV Beast',NULL,NULL,'BEAST-01','needs-attention','assembled','owner',true,'Waveshare tracked UGV with a RoArm-M2 manipulator. First unit of the fleet. Near-term role is remote-piloted utility work; the maiden job is hauling Cat6 ends through the crawlspace.',NULL,NULL,NULL,'2026',NULL,1,25,5,'5V',3200,NULL,NULL,'[{"label":"Chassis","value":"Tracked, all-terrain"},{"label":"Arm","value":"RoArm-M2 · 4-DOF"},{"label":"Onboard host","value":"Raspberry Pi 5"},{"label":"Motor control","value":"ESP32 (PID)"},{"label":"Pack","value":"3S Li-ion (~11.1V)"},{"label":"Control","value":"Remote teleop (FPV)"}]'::jsonb,'[{"label":"Live control dashboard","url":"http://beast.local:5000"},{"label":"JupyterLab (lessons)","url":"http://beast.local:8888"},{"label":"Waveshare UGV Beast","url":"https://www.waveshare.com/ugv-beast.htm"},{"label":"Waveshare UGV hardware tutorial","url":"https://www.youtube.com/watch?v=8wqPs7rNkJ4"}]'::jsonb,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('roarm-m2','module','Waveshare RoArm-M2',NULL,NULL,'ARM-M2','operational','assembled','owner',false,'4-DOF manipulator mounted on BEAST-01 and driven through the serial bus servo chain.',NULL,NULL,NULL,'owned',NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,'[{"label":"Form","value":"4-DOF arm"},{"label":"Drive","value":"ST3215/ST3235 serial bus servos"},{"label":"Host slot","value":"BEAST-01 Serial Bus Servo"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('stock-ups','module','Stock 3x18650 UPS',NULL,NULL,'BEAST-PWR','operational','assembled','owner',false,'Stock undercarriage UPS module installed in BEAST-01, with room for 3x 18650 cells and external 3S pack experiments.',NULL,NULL,NULL,'included',NULL,1,NULL,11.1,'battery',NULL,NULL,NULL,'[{"label":"Cells","value":"3x 18650"},{"label":"Chassis slot","value":"Undercarriage Bay"},{"label":"Expansion","value":"External 3S packs via XH2.54 input"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('rover-slot-2','module','Open Rover Slot',NULL,NULL,NULL,'wishlist','wishlist','inferred',false,'Reserved bay for the next ground unit or aerial drone as the fleet grows.',NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,'[{"label":"Status","value":"Empty — future acquisition"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('workstation','module','Threadripper / RTX 5090',NULL,NULL,'CORE-PRIME','operational','deployed','owner',true,'Blackwell-class desktop. The off-board "cloud brain" for the fleet: trains policies, runs VLM/LLM reasoning, heavy perception — streamed to units over WiFi 6. Compute is never the bottleneck; the network tail is.',NULL,NULL,NULL,'owned',NULL,1,600,NULL,'mains',NULL,NULL,NULL,'[{"label":"GPU","value":"RTX 5090 · 32GB GDDR7"},{"label":"Arch","value":"Blackwell"},{"label":"CPU","value":"Threadripper"},{"label":"Role","value":"Train + offboard inference"},{"label":"Link","value":"WiFi 6 LAN to fleet"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('pi5','module','Raspberry Pi 5',NULL,NULL,'EDGE-PI','operational','assembled','owner',false,'Onboard host on the Beast: teleop, streaming, I/O, and the stale-command watchdog. No CUDA GPU, so learned-policy inference lives offboard on the 5090. Constrained 5V/5A rail is a real design limit.',NULL,NULL,NULL,'owned',NULL,1,25,5,'5V',NULL,NULL,NULL,'[{"label":"SoC","value":"BCM2712 · quad A76"},{"label":"GPU","value":"VideoCore (no CUDA)"},{"label":"Rail","value":"5V / 5A — protect it"},{"label":"Role","value":"Teleop · stream · watchdog"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('orin-nano','module','Jetson Orin Nano Super',NULL,NULL,'ORIN-NX?','researching','wishlist','inferred',false,'Candidate onboard CUDA brain for dropout-proof, in-motion autonomy, and the affordable ($249) edge generative-AI tier — runs vision transformers, LLMs, and VLMs. Ampere GPU + 6-core Arm CPU; the "Super" boost (up to 67 TOPS, ~1.7× the original Orin Nano) ships as a software upgrade to existing kits. Reference carrier accepts all Orin Nano + Orin NX modules and up to 2× 4-lane MIPI CSI cameras, and runs the NVIDIA stack incl. Isaac ROS for robotics. Only needed once the WiFi-offload path is outgrown.',NULL,NULL,NULL,NULL,'buy when autonomy needed',1,25,NULL,'battery',NULL,249,NULL,'[{"label":"AI perf","value":"up to 67 TOPS (Super); ~1.7× prior"},{"label":"Arch","value":"Ampere GPU + 6-core Arm"},{"label":"Power","value":"7–25 W"},{"label":"Memory","value":"8 GB"},{"label":"Cameras","value":"2× MIPI CSI (4-lane)"},{"label":"Carrier","value":"Accepts Orin Nano + Orin NX"},{"label":"Stack","value":"CUDA · TensorRT · Isaac ROS"},{"label":"Lifecycle","value":"through 2032"}]'::jsonb,'[{"label":"NVIDIA Jetson Orin","url":"https://www.nvidia.com/en-us/autonomous-machines/embedded-systems/jetson-orin/"}]'::jsonb,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('jetson-thor','module','Jetson Thor (T4000)',NULL,NULL,NULL,'researching','wishlist','inferred',false,'Blackwell in an embedded module — but the wrong tier for a hobby rover. Built for humanoids and industrial AMRs. Logged for the research horizon, not the buy list.',NULL,NULL,NULL,NULL,'Q2 2026 · wrong tier',1,75,NULL,'battery',NULL,1999,NULL,'[{"label":"AI perf","value":"1,200 FP4 TFLOPS"},{"label":"Arch","value":"Blackwell"},{"label":"Power","value":"40–75 W"},{"label":"Memory","value":"64 GB"},{"label":"Price","value":"~$1,999 @ 1k vol"},{"label":"Avail","value":"~Q2 2026"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('udm-pro-max','module','UniFi UDM Pro Max',NULL,NULL,'GATEWAY','operational','deployed','owner',false,'Core of Network Ops — gateway, controller, and the spine the offload link rides on.',NULL,NULL,'Home Assistant','owned',NULL,1,33,NULL,'mains',NULL,NULL,NULL,'[{"label":"Role","value":"Gateway + UniFi controller"},{"label":"Uplink","value":"10G homelab switching"}]'::jsonb,NULL,NULL,NULL);
INSERT INTO assets(id,kind,name,manufacturer,model,callsign,status,lifecycle,provenance,flagship,summary,description,planning_notes,monitored_via,acquired,horizon,quantity,power_watts,power_volts,power_rail,mass_grams,price_us,price_import,specs,links,limitations,sources) VALUES ('unifi-aps','module','UniFi WiFi 7 APs',NULL,NULL,NULL,'operational','deployed','owner',false,'In-wall + outdoor APs providing the 5GHz / WiFi 6+ coverage the offload architecture depends on. Coverage = autonomy range when the brain is off-board.',NULL,NULL,NULL,'owned',NULL,1,NULL,NULL,NULL,NULL,NULL,NULL,'[{"label":"Units","value":"U7 in-wall + outdoor"},{"label":"Role","value":"Fleet uplink / coverage"}]'::jsonb,NULL,NULL,NULL);
