INSERT INTO capabilities(id,name,description,unlocked) VALUES ('rgbd-perception','Fused RGB-D Perception','Registered colour + depth out of the box, zero calibration burden.',false);
INSERT INTO capabilities(id,name,description,unlocked) VALUES ('long-range-mapping','Long-Range Mapping','Standalone LiDAR geometry at range — gated behind calibration + time-sync work.',false);
