INSERT INTO wishlist_meta(asset_id,asset_lifecycle,rationale,unlocks_capability_id,risk_note,for_asset_id,for_mission_id) VALUES ('light-bar','wishlist','Wide flood, rugged, 2S–3S input — runs off the battery rail, not the Pi. Mount forward + angled down ~15–20° to light the floor without blasting dust at lens level.','night-ops','Import variants vary in driver quality; verify 3S rating.','beast','undercroft');
INSERT INTO wishlist_meta(asset_id,asset_lifecycle,rationale,unlocks_capability_id,risk_note,for_asset_id,for_mission_id) VALUES ('crawler-led-kit','wishlist','Cheapest path — multiple small LEDs you can place and offset individually off the lens axis.','night-ops',NULL,'beast','undercroft');
INSERT INTO wishlist_meta(asset_id,asset_lifecycle,rationale,unlocks_capability_id,risk_note,for_asset_id,for_mission_id) VALUES ('depth-cam','wishlist','Factory-calibrated RGB-D on one USB stream — erases camera intrinsics, extrinsics, and time-sync work. Computes depth onboard, so the host streams it without a GPU. The "reach high but solve power" first step.','rgbd-perception','Compromises max range vs standalone LiDAR.','beast','perimeter-mapping');
INSERT INTO wishlist_meta(asset_id,asset_lifecycle,rationale,unlocks_capability_id,risk_note,for_asset_id,for_mission_id) VALUES ('standalone-lidar','wishlist','Mind-blowing range/coverage but LiDAR-only. Adds extrinsic calibration + time-sync burden, and more total draw — compounds the Pi power problem. Defer until the pipeline exists.','long-range-mapping','Calibration + time-sync + power burden; drifts with vibration on a tracked base.','beast',NULL);
INSERT INTO wishlist_meta(asset_id,asset_lifecycle,rationale,unlocks_capability_id,risk_note,for_asset_id,for_mission_id) VALUES ('audeze-mm100','wishlist','Top of the Audio Lab planar wishlist.',NULL,NULL,'rog-kithara',NULL);
INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('dust-backscatter','Offset lights from the camera lens','In a dusty crawlspace, a light next to the lens illuminates floating dust between camera and target — driving in glowing fog. Mount low/forward, angled down, or off to the side; favour wide flood over spot to avoid hot centres and glare off galvanized duct.','high',NULL,'2026-05-31');
