INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('watchdog','Stale-command watchdog beats latency worries','The risk on WiFi is the tail, not the median. A cheap onboard reflex — "no fresh command in N ms → stop or coast" — turns a dropped packet into a brief pause instead of a crash. Lives on the Pi/ESP32, never depends on the link.','high',NULL,'2026-05-31');
