INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('wifi-tail','WiFi 6 median is great; the tail is the enemy','Local 5GHz / WiFi 6 gives 2–10 ms round trips, low-tens under contention — fine even for tight loops. The danger is the occasional 200 ms stall or half-second gap from roaming, contention, or noise. Design for the worst packet in the window.','high',NULL,'2026-05-31');
