INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('orin-tier','Orin Nano is the stable mainstream entry tier','NVIDIA gave Orin the free "Super" boost and extended its lifecycle through 2032. Buying an Orin Nano Super now is not buying into something about to be discontinued — it is the mainstream tier for years.','high',NULL,'2026-05-31');
