INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('thor-tier','Thor is industrial-tier, wrong size for a rover','Thor (T4000/T5000) targets humanoids and warehouse AMRs that must run large VLA models fully onboard with the power budget to carry a 40–130 W brain. A tracked hobby rover within AP range is not that animal.','high',NULL,'2026-05-31');
