INSERT INTO insights(id,title,body,confidence,source,captured_at) VALUES ('lerobot-optional','LeRobot is an option, not the platform','LeRobot is software you would deliberately install for learned manipulation (ACT, SmolVLA, π0) — not hardware branding you already own. It only matters if the goal becomes the arm learning from demonstrations, versus classical CV + teleop.','medium',NULL,'2026-05-31');
